1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface Customer {
8	  yearsWithMHPCO: number;
9	  contractCount: number;
10	}
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	};
19	
20	const BLOCK_PRICE_FOR_3_ALIKE = 60;
21	const CURSED_SURCHARGE_MULTIPLIER = 1.5;
22	const ENCHANTMENT_SURCHARGE_MULTIPLIER = 0.3;
23	const FIRST_INSURANCE_SURCHARGE_MULTIPLIER = 1.1;
24	const FOLLOW_UP_CONTRACT_DISCOUNT_MULTIPLIER = 0.85;
25	const LOYALTY_DISCOUNT_MULTIPLIER = 0.8;
26	const LOYALTY_DISCOUNT_MIN_YEARS = 2;
27	const HIGH_ENCHANTMENT_THRESHOLD = 5;
28	
29	const roundToCents = (amount: number): number => Math.round(amount * 100) / 100;
30	
31	export function generateQuote(items: Item[], customer: Customer): { basePremium: number } {
32	  const nonCursedCountsByType: Record<string, number> = {};
33	  let cursedPremium = 0;
34	  let enchantmentSurcharge = 0;
35	
36	  for (const item of items) {
37	    const itemBasePremium = BASE_PREMIUMS[item.type];
38	    if (item.cursed) {
39	      cursedPremium += itemBasePremium * CURSED_SURCHARGE_MULTIPLIER;
40	    } else {
41	      nonCursedCountsByType[item.type] = (nonCursedCountsByType[item.type] ?? 0) + 1;
42	      if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
43	        enchantmentSurcharge += itemBasePremium * ENCHANTMENT_SURCHARGE_MULTIPLIER;
44	      }
45	    }
46	  }
47	
48	  let basePremium = cursedPremium;
49	  for (const [type, count] of Object.entries(nonCursedCountsByType)) {
50	    if (count === 3) {
51	      basePremium += BLOCK_PRICE_FOR_3_ALIKE;
52	    } else {
53	      basePremium += count * BASE_PREMIUMS[type];
54	    }
55	  }
56	  basePremium += enchantmentSurcharge;
57	
58	  basePremium *= FIRST_INSURANCE_SURCHARGE_MULTIPLIER;
59	
60	  if (customer.contractCount >= 1) {
61	    basePremium *= FOLLOW_UP_CONTRACT_DISCOUNT_MULTIPLIER;
62	  }
63	
64	  if (customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_MIN_YEARS) {
65	    basePremium *= LOYALTY_DISCOUNT_MULTIPLIER;
66	  }
67	
68	  return { basePremium: roundToCents(basePremium) };
69	}
70	
71	export function processClaim(policy: unknown, incident: unknown): { payout: number; remainingCap: number } {
72	  return undefined as unknown as { payout: number; remainingCap: number };
73	}
